func (this *BigoneCore) ParseOrder(order any, optionalArgs ...any) any {
	//
	//    {
	//        "id": "42154072252",
	//        "asset_pair_name": "SOL-USDT",
	//        "price": "20",
	//        "amount": "0.5",
	//        "filled_amount": "0",
	//        "avg_deal_price": "0",
	//        "side": "ASK",
	//        "state": "PENDING",
	//        "created_at": "2023-09-13T03:42:00Z",
	//        "updated_at": "2023-09-13T03:42:00Z",
	//        "type": "LIMIT",
	//        "stop_price": "0",
	//        "immediate_or_cancel": false,
	//        "post_only": false,
	//        "client_order_id": ''
	//    }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var id any = this.SafeString(order, "id")
	var marketId any = this.SafeString(order, "asset_pair_name")
	var symbol any = this.SafeSymbol(marketId, market, "-")
	var timestamp any = this.Parse8601(this.SafeString(order, "created_at"))
	var side any = this.SafeString(order, "side")
	if IsTrue(IsEqual(side, "BID")) {
		side = "buy"
	} else {
		side = "sell"
	}
	var triggerPrice any = this.SafeString(order, "stop_price")
	if IsTrue(Precise.StringEq(triggerPrice, "0")) {
		triggerPrice = nil
	}
	var immediateOrCancel any = this.SafeBool(order, "immediate_or_cancel")
	var timeInForce any = nil
	if IsTrue(immediateOrCancel) {
		timeInForce = "IOC"
	}
	var typeVar any = this.ParseType(this.SafeString(order, "type"))
	var price any = this.SafeString(order, "price")
	var amount any = nil
	var filled any = nil
	var cost any = nil
	if IsTrue(IsTrue(IsEqual(typeVar, "market")) && IsTrue(IsEqual(side, "buy"))) {
		cost = this.SafeString(order, "filled_amount")
	} else {
		amount = this.SafeString(order, "amount")
		filled = this.SafeString(order, "filled_amount")
	}
	return this.SafeOrder(map[string]any{
		"info":               order,
		"id":                 id,
		"clientOrderId":      this.SafeString(order, "client_order_id"),
		"timestamp":          timestamp,
		"datetime":           this.Iso8601(timestamp),
		"lastTradeTimestamp": this.Parse8601(this.SafeString(order, "updated_at")),
		"symbol":             symbol,
		"type":               typeVar,
		"timeInForce":        timeInForce,
		"postOnly":           this.SafeBool(order, "post_only"),
		"side":               side,
		"price":              price,
		"triggerPrice":       triggerPrice,
		"amount":             amount,
		"cost":               cost,
		"average":            this.SafeString(order, "avg_deal_price"),
		"filled":             filled,
		"remaining":          nil,
		"status":             this.ParseOrderStatus(this.SafeString(order, "state")),
		"fee":                nil,
		"trades":             nil,
	}, market)
}

