func (this *BigoneCore) ParseTransaction(transaction any, optionalArgs ...any) any {
	//
	// fetchDeposits
	//
	//     {
	//         "amount": "25.0",
	//         "asset_symbol": "BTS"
	//         "confirms": 100,
	//         "id": 5,
	//         "inserted_at": "2018-02-16T11:39:58.000Z",
	//         "is_internal": false,
	//         "kind": "default",
	//         "memo": "",
	//         "state": "WITHHOLD",
	//         "txid": "72e03037d144dae3d32b68b5045462b1049a0755",
	//         "updated_at": "2018-11-09T10:20:09.000Z",
	//     }
	//
	// fetchWithdrawals
	//
	//     {
	//         "amount": "5",
	//         "asset_symbol": "ETH",
	//         "completed_at": "2018-03-15T16:13:45.610463Z",
	//         "customer_id": "10",
	//         "id": 10,
	//         "inserted_at": "2018-03-15T16:13:45.610463Z",
	//         "is_internal": true,
	//         "note": "2018-03-15T16:13:45.610463Z",
	//         "state": "CONFIRMED",
	//         "target_address": "0x4643bb6b393ac20a6175c713175734a72517c63d6f7"
	//         "txid": "0x4643bb6b393ac20a6175c713175734a72517c63d6f73a3ca90a15356f2e967da0",
	//     }
	//
	// withdraw
	//
	//     {
	//         "id":1077391,
	//         "customer_id":1082679,
	//         "amount":"21.9000000000000000",
	//         "txid":"",
	//         "is_internal":false,
	//         "kind":"on_chain",
	//         "state":"PENDING",
	//         "inserted_at":"2020-06-03T00:50:57+00:00",
	//         "updated_at":"2020-06-03T00:50:57+00:00",
	//         "memo":"",
	//         "target_address":"rDYtYT3dBeuw376rvHqoZBKW3UmvguoBAf",
	//         "fee":"0.1000000000000000",
	//         "asset_symbol":"XRP"
	//     }
	//
	currency := GetArg(optionalArgs, 0, nil)
	_ = currency
	var currencyId any = this.SafeString(transaction, "asset_symbol")
	var code any = this.SafeCurrencyCode(currencyId)
	var id any = this.SafeString(transaction, "id")
	var amount any = this.SafeNumber(transaction, "amount")
	var status any = this.ParseTransactionStatus(this.SafeString(transaction, "state"))
	var timestamp any = this.Parse8601(this.SafeString(transaction, "inserted_at"))
	var updated any = this.Parse8601(this.SafeString2(transaction, "updated_at", "completed_at"))
	var txid any = this.SafeString(transaction, "txid")
	var address any = this.SafeString(transaction, "target_address")
	var tag any = this.SafeString(transaction, "memo")
	var typeVar any = Ternary(IsTrue((InOp(transaction, "customer_id"))), "withdrawal", "deposit")
	var internal any = this.SafeBool(transaction, "is_internal")
	return map[string]any{
		"info":        transaction,
		"id":          id,
		"txid":        txid,
		"timestamp":   timestamp,
		"datetime":    this.Iso8601(timestamp),
		"network":     nil,
		"addressFrom": nil,
		"address":     nil,
		"addressTo":   address,
		"tagFrom":     nil,
		"tag":         tag,
		"tagTo":       nil,
		"type":        typeVar,
		"amount":      amount,
		"currency":    code,
		"status":      status,
		"updated":     updated,
		"fee":         nil,
		"comment":     nil,
		"internal":    internal,
	}
}

